#include <stdio.h>
#include <stdint.h>
int main() {
    /**
     * Variables are stored as follows:
     * whatWeCouldDoYesterday -- data & 0b11
     * whatWeCanDoToday       -- (data & 0b1100) >> 2
     * answer                 -- (data & 0xff00) >> 8
     * numDays                -- (data & 0xff0000) >> 16
     * todayCode              -- (data & 0xff000000) >> 24
    */

    //whatWeDidYesterday = whatWeCanDoToday = answer = numDays = todayCode = 0;
    uint32_t data = 0;
    //scanf("%i", &numDays);
    scanf("%hhi", ((signed char*)&data)+2);
    //whatWeCouldDoYesterday = 3;
    data += 3;
    //while ((numDays -= 1), numDays+1) {
    while ((data -= 0x10000), ((data+0x10000) & 0xff0000) >> 16) {
        //scanf("%i", &todayCode);
        scanf("%hhi", ((signed char*)&data)+3);
        //if ((whatWeCouldDoYesterday & 2) && (todayCode & 1)) whatWeCanDoToday += 1;
        if ((data & 2) && (data & 0x1000000) >> 24) data += 1 << 2;
        //if ((whatWeCouldDoYesterday & 1) && (todayCode & 2)) whatWeCanDoToday += 2;
        if ((data & 1) && (data & 0x2000000) >> 24) data += 2 << 2;
        //if (!whatWeCanDoToday) answer += 1, whatWeCanDoToday = 3;
        if (!(data & 0b1100)) data += 1 << 8, data += 3 << 2;
        //whatWeCouldDoYesterday = whatWeCanDoToday, whatWeCanDoToday = 0;
        *((signed char*)&data) >>= 2;
    }
    //printf("%i\n", answer);
    printf("%li\n", (data & 0xff00) >> 8);
}

