macro_rules ! min { ( $ x : expr ) => ( $ x ) ; ( $ x : expr , $ ( $ xs : expr ) ,+ ) => { { use std :: cmp :: min ; min ( $ x , min ! ( $ ( $ xs ) ,+ ) ) } } ; }

fn main() {
    let n = get!(usize);
    let a = invec!(usize);
    let mut ans = 0;
    let mut p = 0;
    let mut dp = vec![vec![INF_USIZE; 3]; n + 5];
    dp[0][0] = 0;
    for i in 0..n {
        dp[i + 1][0] = min!(dp[i][0], dp[i][1], dp[i][2]) + 1;
        if a[i] == 1 {
            dp[i + 1][1] = min(dp[i][2], dp[i][0]);
        } else if a[i] == 2 {
            dp[i + 1][2] = min(dp[i][1], dp[i][0]);
        }
        if a[i] == 3 {
            dp[i + 1][1] = min(dp[i][0], dp[i][2]);
            dp[i + 1][2] = min(dp[i][0], dp[i][1]);
        }
    }
    ans = min!(dp[n][0], dp[n][1], dp[n][2]);
    echo!(ans);
}
